import { ActorRefFrom, assign, setup } from "xstate"

import { AbstractAuthSession } from "frontend/state/authentication"

import AuthenticationMachine from "../root/root-machine"

export interface AuthenticationContext {
  authSession?: AbstractAuthSession
}

export type Events = {
  type: "done.invoke.AuthenticationMachine"
  output: any
}

const NFIDAuthMachineConfig = {
  /** @xstate-layout -n+MVxQlyUdgoYAcBwtFMCIUgjAAZrRr5MJl-R4Dlym0QVVrscVlRwT8bxnFUeSVG6pYJEKZ4nJc4SxJK5QSXKJBUPA+wtp14bdWwnDcHwAhCKIEjSLI-KODZbFFaV6EciKoo1RUwnnB10nvWqn1cBt0EIHax52iEQWYaVdpiRUySI8qyPgr0-SDMM8LztMqjo3ZzVnj8JTJEK4rlD42MVEwh6RPWVYJKV1zJCTQavUjz6RhqMKxmDFq2VtnHRHD1xnaEbVRCWdUHkwyFCikpxRHu4v-ARUvEZ2thTjOA5gIzW2vMcxSJDuRTrkhx7XQUosnJhhsyqTbZW0wb4fl+ti9dFSsgIrYP0mUjkfHmKS2qcmvoQhyTQ28e7Xarh7B2F3XyYMFG5Sp+XWRmhX0my+QHoUh7xJrqQefyFTPDDUoxF5AvF11arflF-6fgNSWyY7RUSuyBTREh1xlK7W7HvW0QvFVvc7cksRSoP5NyXgEDT6u5y7ZrjrrjtKSRN75xnsEtqHVceQIxLD5k9LDs18udm2sebAc88ZVTFlud2A96i1CAA */
  id: "auth-machine",
  initial: "AuthenticationMachine",
  context: {} as AuthenticationContext,
  states: {
    AuthenticationMachine: {
      invoke: {
        src: "AuthenticationMachine",
        id: "AuthenticationMachine",
        onDone: { target: "End", actions: "assignAuthSession" },
        input: {
          verificationEmail: "",
          authRequest: {
            hostname: window.location.origin,
          },
        },
      },
    },
    End: {
      type: "final" as const,
    },
  },
}

const NFIDAuthMachineOptions = {
  actions: {
    assignAuthSession: assign(({ event }: any) => {
      // eslint-disable-next-line no-console
      console.debug("[NFIDAuthMachine] done.invoke.AuthenticationMachine", {
        hasOutput: event?.output != null,
        outputKeys: event?.output ? Object.keys(event.output) : null,
      })
      return {
        // AuthenticationMachine outputs the full auth context, with `authSession` nested.
        authSession: event?.output?.authSession ?? event?.output,
      }
    }),
  },
  actors: {
    AuthenticationMachine,
  },
}

const NFIDAuthMachine = setup({
  types: {} as {
    context: AuthenticationContext
    events: any
    output: unknown
  },
  ...NFIDAuthMachineOptions,
} as any).createMachine(NFIDAuthMachineConfig as any)

export type NFIDAuthMachineActor = ActorRefFrom<typeof NFIDAuthMachine>
export type NFIDAuthMachineType = typeof NFIDAuthMachine
export default NFIDAuthMachine
